"""PackRuntime for workspace validation and packaging."""
import os
import glob
from pathlib import Path
from typing import Dict, Any, Optional, Tuple
from rich.console import Console

from agentcube.models.metadata import AgentMetadata, KubernetesDeployment
from agentcube.services.metadata import MetadataService

console = Console()


class PackRuntime:
    """Runtime for validating agent workspace and preparing packages."""

    def __init__(self, verbose: bool = False) -> None:
        self.verbose = verbose

    def pack(self, workspace_path: Path, **options: Any) -> Dict[str, Any]:
        """Pack agent workspace."""
        if self.verbose:
            console.print(f"[blue]Packing workspace: {workspace_path}[/blue]")

        # Validate workspace exists
        self._validate_workspace_structure(workspace_path)

        # Load or create metadata
        metadata = self._load_or_create_metadata(workspace_path, options)

        # Apply CLI option overrides
        metadata = self._apply_option_overrides(metadata, options)

        # Validate language compatibility
        self._validate_language_compatibility(workspace_path, metadata)

        # Process dependencies
        self._process_dependencies(workspace_path, metadata)

        # Generate Dockerfile
        dockerfile_path = self._generate_dockerfile(workspace_path, metadata)

        # Update pack metadata
        self._update_pack_metadata(workspace_path, metadata, dockerfile_path)

        return {
            "agent_name": metadata.agent_name,
            "workspace_path": str(workspace_path),
            "metadata_path": str(workspace_path / "agent_metadata.yaml"),
            "dockerfile_path": str(dockerfile_path) if dockerfile_path else None,
        }

    def _validate_workspace_structure(self, workspace_path: Path) -> None:
        """Validate that the workspace path exists and is a directory."""
        if not workspace_path.exists():
            raise ValueError(f"Workspace directory does not exist: {workspace_path}")
        if not workspace_path.is_dir():
            raise ValueError(f"Workspace path is not a directory: {workspace_path}")

    def _load_or_create_metadata(self, workspace_path: Path, options: Dict[str, Any]) -> AgentMetadata:
        """Load existing metadata or create new."""
        metadata = MetadataService.load_metadata(str(workspace_path))
        if metadata:
            if self.verbose:
                console.print(f"[blue]Loaded existing metadata[/blue]")
            return metadata

        # Create new metadata
        return AgentMetadata(
            agent_name=options.get("agent_name") or "my-agent",
            language=options.get("language") or "python",
            version="0.1.0",
            entrypoint=options.get("entrypoint"),
            port=options.get("port") or 8080,
            build_mode=options.get("build_mode") or "local",
            description=options.get("description"),
        )

    def _apply_option_overrides(self, metadata: AgentMetadata, options: Dict[str, Any]) -> AgentMetadata:
        """Apply CLI option overrides to metadata."""
        if options.get("agent_name"):
            metadata.agent_name = options["agent_name"]
        if options.get("language"):
            metadata.language = options["language"]
        if options.get("entrypoint"):
            metadata.entrypoint = options["entrypoint"]
        if options.get("port"):
            metadata.port = options["port"]
        if options.get("build_mode"):
            metadata.build_mode = options["build_mode"]
        if options.get("description"):
            metadata.description = options["description"]
        return metadata

    def _validate_language_compatibility(self, workspace_path: Path, metadata: AgentMetadata) -> None:
        """Validate workspace language compatibility."""
        language = metadata.language.lower()

        if language == "python":
            self._validate_python_compatibility(workspace_path)
        elif language == "java":
            self._validate_java_compatibility(workspace_path)

    def _validate_python_compatibility(self, workspace_path: Path) -> None:
        """Validate Python workspace has at least one .py file."""
        py_files = list(workspace_path.glob("*.py"))
        if not py_files:
            raise ValueError("No Python files found in workspace")
        if self.verbose:
            console.print(f"[blue]Found {len(py_files)} Python files[/blue]")

    def _validate_java_compatibility(self, workspace_path: Path) -> None:
        """Validate Java workspace has pom.xml."""
        pom_file = workspace_path / "pom.xml"
        if not pom_file.exists():
            raise ValueError("Java workspace requires pom.xml")
        if self.verbose:
            console.print(f"[blue]Found pom.xml[/blue]")

    def _process_dependencies(self, workspace_path: Path, metadata: AgentMetadata) -> None:
        """Process dependencies for the workspace."""
        language = metadata.language.lower()

        if language == "python":
            self._process_python_dependencies(workspace_path)
        elif language == "java":
            self._process_java_dependencies(workspace_path)

    def _process_python_dependencies(self, workspace_path: Path) -> None:
        """Process Python dependencies."""
        req_file = workspace_path / "requirements.txt"
        if req_file.exists():
            if self.verbose:
                console.print(f"[blue]Found requirements.txt[/blue]")

    def _process_java_dependencies(self, workspace_path: Path) -> None:
        """Process Java dependencies."""
        pom_file = workspace_path / "pom.xml"
        if pom_file.exists():
            if self.verbose:
                console.print(f"[blue]Found pom.xml[/blue]")

    def _generate_dockerfile(self, workspace_path: Path, metadata: AgentMetadata) -> Optional[Path]:
        """Generate Dockerfile for the agent."""
        dockerfile_path = workspace_path / "Dockerfile"

        language = metadata.language.lower()
        entrypoint = metadata.entrypoint or self._infer_entrypoint(workspace_path, language)
        port = metadata.port or 8080

        if language == "python":
            content = self._generate_python_dockerfile(entrypoint, port)
        elif language == "java":
            content = self._generate_java_dockerfile(entrypoint, port)
        else:
            content = self._generate_generic_dockerfile(entrypoint, port)

        with open(dockerfile_path, "w") as f:
            f.write(content)

        if self.verbose:
            console.print(f"[blue]Generated Dockerfile: {dockerfile_path}[/blue]")

        return dockerfile_path

    def _infer_entrypoint(self, workspace_path: Path, language: str) -> str:
        """Infer entrypoint from workspace."""
        if language == "python":
            py_files = list(workspace_path.glob("*.py"))
            if py_files:
                return py_files[0].name
            return "app.py"
        elif language == "java":
            return "app.jar"
        return "app"

    def _generate_python_dockerfile(self, entrypoint: str, port: int) -> str:
        """Generate Python Dockerfile."""
        return f'''FROM python:3.11-slim

WORKDIR /app

COPY requirements.txt .
RUN pip install --no-cache-dir -r requirements.txt

COPY . .

EXPOSE {port}

CMD ["python", "{entrypoint}"]
'''

    def _generate_java_dockerfile(self, entrypoint: str, port: int) -> str:
        """Generate Java Dockerfile."""
        return f'''FROM maven:3.9-eclipse-temurin-17-alpine AS build

WORKDIR /app
COPY pom.xml .
RUN mvn dependency:go-offline

COPY src ./src
RUN mvn package -DskipTests

FROM eclipse-temurin:17-jre-alpine

WORKDIR /app
COPY --from=build /app/target/*.jar app.jar

EXPOSE {port}

ENTRYPOINT ["java", "-jar", "app.jar"]
'''

    def _generate_generic_dockerfile(self, entrypoint: str, port: int) -> str:
        """Generate generic Dockerfile."""
        return f'''FROM alpine:latest

WORKDIR /app

COPY . .

EXPOSE {port}

CMD ["./{entrypoint}"]
'''

    def _update_pack_metadata(self, workspace_path: Path, metadata: AgentMetadata, 
                              dockerfile_path: Optional[Path]) -> None:
        """Update metadata after pack."""
        MetadataService.save_metadata(str(workspace_path), metadata)
        if self.verbose:
            console.print(f"[blue]Updated metadata[/blue]")

    @staticmethod
    def _resolve_workspace(workspace: str) -> Path:
        """Resolve workspace path."""
        path = Path(workspace).resolve()
        if not path.exists():
            raise ValueError(f"Workspace does not exist: {path}")
        if not path.is_dir():
            raise ValueError(f"Workspace is not a directory: {path}")
        return path

    @staticmethod
    def validate_workspace(workspace: str, language: str) -> Tuple[bool, str]:
        """Validate workspace for language compatibility."""
        workspace_path = Path(workspace)

        if not workspace_path.exists():
            return False, f"Workspace does not exist: {workspace}"

        if not workspace_path.is_dir():
            return False, f"Workspace is not a directory: {workspace}"

        language = language.lower()

        if language == "python":
            py_files = list(workspace_path.glob("*.py"))
            if not py_files:
                return False, "No Python files found in workspace"
        elif language == "java":
            pom_file = workspace_path / "pom.xml"
            if not pom_file.exists():
                return False, "Java workspace requires pom.xml"

        return True, "Workspace validated successfully"

"""InvokeRuntime for HTTP calls."""
import json
from pathlib import Path
from typing import Dict, Any, Optional, List
import requests
from rich.console import Console

from agentcube.models.metadata import AgentMetadata
from agentcube.services.metadata import MetadataService

console = Console()


class InvokeRuntime:
    """Runtime for invoking agents."""

    def __init__(self, verbose: bool = False, provider: str = "agentcube") -> None:
        self.verbose = verbose
        self.provider = provider

    def invoke(self, workspace_path: Path, payload: str, 
               header_list: Optional[List[str]]) -> Dict[str, Any]:
        """Invoke the agent with given payload."""
        if self.verbose:
            console.print(f"[blue]Invoking agent[/blue]")

        # Load metadata
        metadata = MetadataService.load_metadata(str(workspace_path))
        if not metadata:
            raise ValueError(f"No metadata found in workspace: {workspace_path}")

        # Validate payload is JSON
        try:
            json_payload = json.loads(payload)
        except json.JSONDecodeError as e:
            console.print(f"[red]Invalid JSON payload: {e}[/red]")
            raise typer.Exit(code=1)

        # Parse headers
        headers = {}
        if header_list:
            for header in header_list:
                parts = header.split(":", 1)
                if len(parts) != 2:
                    console.print(f"[red]Invalid header format '{header}'. Expected 'key:value'[/red]")
                    raise typer.Exit(code=1)
                headers[parts[0].strip()] = parts[1].strip()

        # Get endpoint URL
        endpoint, base_url = self._validate_invoke_prerequisites(workspace_path)

        # For AgentRuntime with k8s_deployment.type == "AgentRuntime"
        if (metadata.k8s_deployment and 
            metadata.k8s_deployment.type == "AgentRuntime" and 
            metadata.router_url and metadata.agent_name and metadata.k8s_deployment.namespace):
            url = f"{metadata.router_url}/v1/namespaces/{metadata.k8s_deployment.namespace}/agent-runtimes/{metadata.agent_name}/invocations/"
        elif base_url:
            url = base_url
        else:
            raise ValueError("Could not determine endpoint URL. Ensure agent is published.")

        # Add session header if available
        if metadata.session_id:
            headers["X-AgentCube-Session-Id"] = metadata.session_id

        if self.verbose:
            console.print(f"[blue]Sending request to: {url}[/blue]")
            console.print(f"[blue]Headers: {headers}[/blue]")
            console.print(f"[blue]Payload: {json.dumps(json_payload, indent=2)}[/blue]")

        # Make request
        try:
            response = requests.post(url, json=json_payload, headers=headers, timeout=30)

            result = {
                "status_code": response.status_code,
                "body": response.json() if response.headers.get('content-type', '').startswith('application/json') else response.text
            }

            if response.status_code >= 400:
                raise RuntimeError(f"Request failed with status {response.status_code}: {result['body']}")

            return result

        except requests.exceptions.RequestException as e:
            raise RuntimeError(f"Request failed: {e}")

    def _validate_invoke_prerequisites(self, workspace_path: Path) -> tuple:
        """Validate invoke prerequisites."""
        metadata = MetadataService.load_metadata(str(workspace_path))
        if not metadata:
            raise ValueError("No metadata found")

        if not metadata.agent_id:
            raise ValueError("Agent not published. Run 'publish' first.")

        # Determine base URL
        base_url = None
        if metadata.router_url:
            base_url = metadata.router_url
        elif metadata.k8s_deployment and metadata.k8s_deployment.service_url:
            base_url = metadata.k8s_deployment.service_url
        elif metadata.agent_endpoint:
            base_url = metadata.agent_endpoint

        return metadata.agent_id, base_url


