        self.verbose = verbose
        self.provider = provider

    def get_status(self, workspace_path: Path, provider: Optional[str] = None) -> Dict[str, Any]:
        """Get status info for the agent."""
        prov = provider or self.provider

        # Load metadata
        metadata = MetadataService.load_metadata(str(workspace_path))
        if not metadata:
            raise ValueError(f"No metadata found in workspace: {workspace_path}")

        # Check if agent_id exists
        if not metadata.agent_id:
            return {
                "agent_name": metadata.agent_name,
                "status": "not_published",
                "message": "Agent not published. Run 'publish' first.",
            }

        # Get status based on provider
        if prov == "agentcube":
            status_info = self._get_agentcube_status(metadata)
        elif prov == "k8s":
            status_info = self._get_k8s_status(metadata)
        else:
            return {
                "agent_name": metadata.agent_name,
                "status": "error",
                "message": f"Unknown provider: {prov}",
            }

        # Add metadata info
        status_info["agent_name"] = metadata.agent_name
        status_info["version"] = metadata.version
        status_info["language"] = metadata.language
        status_info["agent_id"] = metadata.agent_id
        status_info["session_id"] = metadata.session_id

        return status_info

    def _get_agentcube_status(self, metadata: AgentMetadata) -> Dict[str, Any]:
